import { ColoredRange } from '@dynatrace/strato-components/charts';

export const replaceInfiniteValuesInRanges = (
  ranges: ColoredRange[],
  domain: [number, number],
) => {
  const replaceInfiniteValues = (value: number) => {
    if (value === -Infinity) {
      if (domain[0] >= 0) {
        return 0;
      } else {
        return domain[0];
      }
    }
    if (value === Infinity) {
      if (domain[1] <= 0) {
        return 0;
      } else {
        return domain[1];
      }
    }
    return value;
  };

  return ranges.map((range: ColoredRange) => {
    return {
      ...range,
      from: replaceInfiniteValues(range.from),
      to: replaceInfiniteValues(range.to),
    };
  });
};
